    {
      "action": "research",
      "goal": "Understand the overall structure and objectives of the CS50 L0 Scratch module."
    },
    {
      "action": "study_notes",
      "goal": "Create detailed notes on core Scratch blocks, sequencing, loops, and conditionals."
