    {
      "action": "key_concepts",
      "goal": "Identify and define the fundamental programming concepts (variables, motion, events) used in Scratch."
    },
    {
      "action": "summarize",
      "goal": "Condense the learned concepts into a high-level summary for quick review."
    },
    {
      "action": "quiz",
      "goal": "Test overall understanding by attempting practice questions related to Scratch logic."
    }
  ]
}

{
